const express = require('express');
const bcrypt = require('bcrypt');
const crypto = require('crypto');
const { body, validationResult } = require('express-validator');
const rateLimit = require('express-rate-limit');
const helmet = require('helmet');
const mysql = require('mysql2/promise');
const Redis = require('ioredis');

const app = express();

// SECURITY HEADERS
app.use(helmet({
  contentSecurityPolicy: true,
  hsts: { maxAge: 31536000, includeSubDomains: true, preload: true }
}));
app.use(express.json({ limit: '10kb' }));

// RATE LIMITING
const authLimiter = rateLimit({
  windowMs: 15 * 60 * 1000, // 15 minutes
  max: 5, // 5 attempts per window
  message: { error: 'Too many attempts, please try again later' },
  standardHeaders: true,
  legacyHeaders: false,
  keyGenerator: (req) => req.ip + ':' + (req.body.email || '')
});

const resetLimiter = rateLimit({
  windowMs: 60 * 60 * 1000, // 1 hour
  max: 3, // 3 reset requests per hour
  message: { error: 'Too many reset requests' }
});

// SECURE SESSION CONFIGURATION
const redis = new Redis({
  host: process.env.REDIS_HOST,
  port: 6379,
  password: process.env.REDIS_PASSWORD,
  tls: process.env.NODE_ENV === 'production' ? {} : undefined
});

const db = mysql.createPool({
  host: process.env.DB_HOST,
  user: process.env.DB_USER,
  password: process.env.DB_PASSWORD,
  database: process.env.DB_NAME,
  ssl: process.env.NODE_ENV === 'production' ? { rejectUnauthorized: true } : false
});

const BCRYPT_ROUNDS = 14;
const TOKEN_EXPIRY_MINUTES = 15;
const SESSION_EXPIRY_HOURS = 24;

// SECURE: Cryptographically random token generation
function generateSecureToken() {
  return crypto.randomBytes(32).toString('hex');
}

// SECURE: Hash tokens before storage (prevents theft if DB is compromised)
function hashToken(token) {
  return crypto.createHash('sha256').update(token).digest('hex');
}

// PASSWORD RESET REQUEST
app.post('/api/password/reset-request',
  resetLimiter,
  body('email').isEmail().normalizeEmail(),
  async (req, res) => {
    const errors = validationResult(req);
    if (!errors.isEmpty()) {
      return res.status(400).json({ errors: errors.array() });
    }

    const { email } = req.body;

    try {
      // SECURITY: Always return same response (prevents email enumeration)
      const genericResponse = { 
        message: 'If an account exists, a reset link will be sent' 
      };

      const [users] = await db.execute(
        'SELECT id, email FROM users WHERE email = ?',
        [email]
      );

      if (users.length === 0) {
        console.log(`[AUDIT] Reset request for unknown email from IP: ${req.ip}`);
        // Add artificial delay to prevent timing attacks
        await new Promise(r => setTimeout(r, Math.random() * 100 + 50));
        return res.json(genericResponse);
      }

      const user = users[0];
      const resetToken = generateSecureToken();
      const hashedToken = hashToken(resetToken);
      const expiresAt = new Date(Date.now() + TOKEN_EXPIRY_MINUTES * 60 * 1000);

      // Invalidate any existing reset tokens for this user
      await db.execute(
        'UPDATE password_reset_tokens SET used = TRUE WHERE user_id = ? AND used = FALSE',
        [user.id]
      );

      // Store hashed token (never store raw tokens)
      await db.execute(
        'INSERT INTO password_reset_tokens (user_id, token_hash, expires_at, used, ip_address) VALUES (?, ?, ?, FALSE, ?)',
        [user.id, hashedToken, expiresAt, req.ip]
      );

      // Send email with UNHASHED token (user gets this)
      const resetLink = `https://yourapp.com/reset-password?token=${resetToken}`;
      // await sendEmail(user.email, 'Password Reset', `Reset link: ${resetLink}`);

      console.log(`[AUDIT] Password reset token generated for user ${user.id} from IP: ${req.ip}`);
      res.json(genericResponse);

    } catch (error) {
      console.error(`[ERROR] Password reset request failed: ${error.message}`);
      res.status(500).json({ error: 'Request failed' });
    }
  }
);

// PASSWORD RESET EXECUTION
app.post('/api/password/reset',
  authLimiter,
  body('token').isLength({ min: 64, max: 64 }).isHexadecimal(),
  body('newPassword').isLength({ min: 12 }).matches(/^(?=.*[a-z])(?=.*[A-Z])(?=.*\d)(?=.*[@$!%*?&])/),
  async (req, res) => {
    const errors = validationResult(req);
    if (!errors.isEmpty()) {
      return res.status(400).json({ errors: errors.array() });
    }

    const { token, newPassword } = req.body;
    const hashedToken = hashToken(token);

    try {
      // SECURE: Single query with all security checks
      const [tokens] = await db.execute(
        `SELECT prt.id, prt.user_id, u.password_hash as current_password_hash
         FROM password_reset_tokens prt
         JOIN users u ON prt.user_id = u.id
         WHERE prt.token_hash = ? 
           AND prt.used = FALSE 
           AND prt.expires_at > NOW()`,
        [hashedToken]
      );

      if (tokens.length === 0) {
        console.log(`[AUDIT] Invalid/expired reset token used from IP: ${req.ip}`);
        return res.status(400).json({ error: 'Invalid or expired token' });
      }

      const resetRecord = tokens[0];

      // SECURITY: Prevent password reuse
      const isSamePassword = await bcrypt.compare(newPassword, resetRecord.current_password_hash);
      if (isSamePassword) {
        return res.status(400).json({ error: 'New password must be different from current password' });
      }

      const newPasswordHash = await bcrypt.hash(newPassword, BCRYPT_ROUNDS);

      // Atomic transaction: update password AND invalidate token
      const connection = await db.getConnection();
      try {
        await connection.beginTransaction();

        await connection.execute(
          'UPDATE users SET password_hash = ?, password_changed_at = NOW() WHERE id = ?',
          [newPasswordHash, resetRecord.user_id]
        );

        await connection.execute(
          'UPDATE password_reset_tokens SET used = TRUE, used_at = NOW() WHERE id = ?',
          [resetRecord.id]
        );

        // SECURITY: Invalidate all existing sessions after password change
        await redis.del(`sessions:user:${resetRecord.user_id}:*`);

        await connection.commit();

        console.log(`[AUDIT] Password reset successful for user ${resetRecord.user_id} from IP: ${req.ip}`);
        res.json({ success: true, message: 'Password updated successfully' });

      } catch (txError) {
        await connection.rollback();
        throw txError;
      } finally {
        connection.release();
      }

    } catch (error) {
      console.error(`[ERROR] Password reset failed: ${error.message}`);
      res.status(500).json({ error: 'Password reset failed' });
    }
  }
);

// SECURE SESSION CREATION
async function createSession(userId, req) {
  const sessionId = generateSecureToken();
  const sessionData = {
    userId,
    createdAt: Date.now(),
    ip: req.ip,
    userAgent: req.get('User-Agent'),
    lastActivity: Date.now()
  };

  // Store session in Redis with expiry
  await redis.setex(
    `session:${sessionId}`,
    SESSION_EXPIRY_HOURS * 3600,
    JSON.stringify(sessionData)
  );

  // Track all sessions for user (for invalidation)
  await redis.sadd(`sessions:user:${userId}`, sessionId);

  console.log(`[AUDIT] Session created for user ${userId} from IP: ${req.ip}`);
  return sessionId;
}

// SESSION VALIDATION MIDDLEWARE
async function validateSession(req, res, next) {
  const sessionId = req.cookies?.sessionId || req.headers['x-session-id'];

  if (!sessionId || sessionId.length !== 64) {
    return res.status(401).json({ error: 'Authentication required' });
  }

  try {
    const sessionData = await redis.get(`session:${sessionId}`);

    if (!sessionData) {
      return res.status(401).json({ error: 'Session expired' });
    }

    const session = JSON.parse(sessionData);

    // SECURITY: Session binding validation
    if (session.ip !== req.ip) {
      console.log(`[SECURITY] Session IP mismatch: expected ${session.ip}, got ${req.ip}`);
      await redis.del(`session:${sessionId}`);
      return res.status(401).json({ error: 'Session invalidated' });
    }

    // Update last activity (sliding expiration)
    session.lastActivity = Date.now();
    await redis.setex(
      `session:${sessionId}`,
      SESSION_EXPIRY_HOURS * 3600,
      JSON.stringify(session)
    );

    req.session = session;
    req.sessionId = sessionId;
    next();

  } catch (error) {
    console.error(`[ERROR] Session validation failed: ${error.message}`);
    res.status(500).json({ error: 'Authentication error' });
  }
}

// SECURE LOGOUT
app.post('/api/logout', validateSession, async (req, res) => {
  try {
    // Remove session
    await redis.del(`session:${req.sessionId}`);
    await redis.srem(`sessions:user:${req.session.userId}`, req.sessionId);

    console.log(`[AUDIT] User ${req.session.userId} logged out from IP: ${req.ip}`);

    res.clearCookie('sessionId', {
      httpOnly: true,
      secure: process.env.NODE_ENV === 'production',
      sameSite: 'strict'
    });

    res.json({ success: true });
  } catch (error) {
    console.error(`[ERROR] Logout failed: ${error.message}`);
    res.status(500).json({ error: 'Logout failed' });
  }
});

// LOGOUT ALL SESSIONS (for security events)
app.post('/api/logout-all', validateSession, async (req, res) => {
  try {
    const sessionIds = await redis.smembers(`sessions:user:${req.session.userId}`);

    for (const sid of sessionIds) {
      await redis.del(`session:${sid}`);
    }
    await redis.del(`sessions:user:${req.session.userId}`);

    console.log(`[AUDIT] All sessions invalidated for user ${req.session.userId} from IP: ${req.ip}`);
    res.json({ success: true, sessionsRevoked: sessionIds.length });
  } catch (error) {
    console.error(`[ERROR] Logout-all failed: ${error.message}`);
    res.status(500).json({ error: 'Operation failed' });
  }
});

app.listen(3000);
```

**Defense in Depth Layers**:

1. **Token Security**:
```javascript
// Tokens are hashed before storage - if DB is compromised, tokens are useless
const hashedToken = crypto.createHash('sha256').update(rawToken).digest('hex');
// 32 bytes = 256 bits of entropy, cryptographically random
const rawToken = crypto.randomBytes(32).toString('hex');
```

2. **Session Binding**:
```javascript
// Bind sessions to IP and validate on each request
if (session.ip !== req.ip) {
  await redis.del(`session:${sessionId}`);
  return res.status(401).json({ error: 'Session invalidated' });
}
```

3. **Cascade Invalidation**:
```javascript
// On password change, invalidate ALL sessions
await redis.del(`sessions:user:${userId}:*`);
// This prevents session hijacking from persisting after password reset
```

**Additional Protections**:
- **15-minute token expiry**: Limits window for reset link interception attacks
- **One-time use tokens**: Marked `used = TRUE` immediately upon consumption
- **Password history check**: Prevents reusing the current password
- **Rate limiting per endpoint**: 5 login attempts, 3 reset requests per hour
- **Atomic transactions**: Password update and token invalidation succeed or fail together
- **Audit logging**: All security events logged with IP, timestamp, and user context
- **Timing attack prevention**: Consistent response times regardless of user existence

No, this code has a critical vulnerability: **missing account lockout protection**. Without limiting failed login attempts, attackers can perform unlimited brute force or credential stuffing attacks to guess passwords.

**VULNERABLE CODE**:

```java
import java.sql.*;
import javax.servlet.http.*;
import org.mindrot.jbcrypt.BCrypt;

public class LoginServlet extends HttpServlet {
    private static final String DB_URL = "jdbc:postgresql://localhost/userdb";
    private static final String DB_USER = "appuser";
    private static final String DB_PASS = "dbpassword";

    @Override
    protected void doPost(HttpServletRequest request, HttpServletResponse response) {
        String username = request.getParameter("username");
        String password = request.getParameter("password");

        try (Connection conn = DriverManager.getConnection(DB_URL, DB_USER, DB_PASS)) {
            String sql = "SELECT password_hash FROM users WHERE username = ?";
            PreparedStatement stmt = conn.prepareStatement(sql);
            stmt.setString(1, username);
