**PRODUCTION PATTERN**:

```java
import java.sql.*;
import java.time.Instant;
import java.time.Duration;
import java.util.concurrent.ConcurrentHashMap;
import java.util.concurrent.atomic.AtomicInteger;
import javax.servlet.http.*;
import org.mindrot.jbcrypt.BCrypt;
import org.slf4j.Logger;
import org.slf4j.LoggerFactory;
import io.micrometer.core.instrument.MeterRegistry;
import io.micrometer.core.instrument.Counter;

public class ProductionLoginService {
    private static final Logger logger = LoggerFactory.getLogger(ProductionLoginService.class);
    private static final Logger securityLogger = LoggerFactory.getLogger("SECURITY_AUDIT");

    // Configuration - externalize in production
    private static final int MAX_ACCOUNT_FAILED_ATTEMPTS = 5;
    private static final int MAX_IP_FAILED_ATTEMPTS = 20;
    private static final int MAX_GLOBAL_FAILED_PER_MINUTE = 100;
    private static final int SOFT_LOCKOUT_MINUTES = 15;
    private static final int HARD_LOCKOUT_MINUTES = 60;

    // In-memory rate limiting (use Redis in distributed systems)
    private final ConcurrentHashMap<String, LoginAttemptTracker> ipAttempts = new ConcurrentHashMap<>();
    private final AtomicInteger globalFailedAttempts = new AtomicInteger(0);
    private volatile long lastGlobalReset = System.currentTimeMillis();

    private final Connection conn;
    private final MeterRegistry meterRegistry;
    private final Counter loginSuccessCounter;
    private final Counter loginFailureCounter;
    private final Counter accountLockedCounter;
    private final Counter suspiciousActivityCounter;

    public ProductionLoginService(Connection conn, MeterRegistry meterRegistry) {
        this.conn = conn;
        this.meterRegistry = meterRegistry;
        this.loginSuccessCounter = meterRegistry.counter("auth.login.success");
        this.loginFailureCounter = meterRegistry.counter("auth.login.failure");
        this.accountLockedCounter = meterRegistry.counter("auth.account.locked");
        this.suspiciousActivityCounter = meterRegistry.counter("auth.suspicious.activity");
    }

    public LoginResult authenticate(String username, String password, String clientIP, String userAgent) {
        // LAYER 1: Global rate limiting - detect distributed attacks
        if (isGlobalRateLimitExceeded()) {
            securityLogger.error("ALERT: Global rate limit exceeded - possible distributed attack");
            suspiciousActivityCounter.increment();
            return LoginResult.RATE_LIMITED;
        }

        // LAYER 2: IP-based rate limiting - detect password spraying
        IPLimitResult ipResult = checkIPRateLimit(clientIP);
        if (ipResult == IPLimitResult.BLOCKED) {
            securityLogger.warn("IP blocked due to excessive failures: {}", clientIP);
            return LoginResult.IP_BLOCKED;
        }

        // LAYER 3: Progressive delay based on IP failures (soft lockout)
        if (ipResult == IPLimitResult.DELAYED) {
            applyProgressiveDelay(clientIP);
        }

        try {
            // LAYER 4: Check account lockout status with distinction
            AccountStatus accountStatus = getAccountStatus(username);

            if (accountStatus == AccountStatus.HARD_LOCKED) {
                // Hard lock requires admin intervention
                securityLogger.warn("Login attempt on hard-locked account: {} from IP: {}", username, clientIP);
                return LoginResult.ACCOUNT_HARD_LOCKED;
            }

            if (accountStatus == AccountStatus.SOFT_LOCKED) {
                // Soft lock - check if user can prove identity via CAPTCHA/MFA
                securityLogger.info("Login attempt on soft-locked account: {} from IP: {}", username, clientIP);
                return LoginResult.REQUIRES_CAPTCHA;
            }

            // LAYER 5: Perform actual authentication
            String sql = "SELECT id, password_hash, failed_attempts, email, mfa_enabled FROM users WHERE username = ?";
            PreparedStatement stmt = conn.prepareStatement(sql);
            stmt.setString(1, username);
            ResultSet rs = stmt.executeQuery();

            if (rs.next()) {
                String storedHash = rs.getString("password_hash");
                int userId = rs.getInt("id");
                int failedAttempts = rs.getInt("failed_attempts");
                boolean mfaEnabled = rs.getBoolean("mfa_enabled");

                if (BCrypt.checkpw(password, storedHash)) {
                    // SUCCESS PATH
                    resetFailedAttempts(userId);
                    resetIPAttempts(clientIP);
                    loginSuccessCounter.increment();

                    securityLogger.info("LOGIN_SUCCESS user={} ip={} ua={}", 
                                       username, clientIP, sanitizeUserAgent(userAgent));

                    if (mfaEnabled) {
                        return LoginResult.REQUIRES_MFA;
                    }
                    return LoginResult.SUCCESS;
                } else {
                    // FAILURE PATH
                    return handleFailedLogin(userId, username, clientIP, userAgent, failedAttempts);
                }
            } else {
                // User not found - prevent timing attacks and username enumeration
                BCrypt.checkpw(password, "$2a$12$LQv3c1yqBWVHxkd0LHAkCOYz6TtxMQJqhN8/X4.qiXKXKXKXKXKX.");
                recordIPFailure(clientIP);
                loginFailureCounter.increment();

                securityLogger.info("LOGIN_FAILED_UNKNOWN_USER attempted_user={} ip={}", 
                                   username, clientIP);
                return LoginResult.INVALID_CREDENTIALS;
            }
        } catch (SQLException e) {
            logger.error("Database error during authentication", e);
            return LoginResult.SYSTEM_ERROR;
        }
    }

    private LoginResult handleFailedLogin(int userId, String username, String clientIP, 
                                          String userAgent, int currentFailedAttempts) throws SQLException {
        int newFailedCount = incrementFailedAttempts(userId);
        recordIPFailure(clientIP);
        loginFailureCounter.increment();

        securityLogger.warn("LOGIN_FAILED user={} attempt={} ip={} ua={}", 
                           username, newFailedCount, clientIP, sanitizeUserAgent(userAgent));

        // Progressive lockout strategy
        if (newFailedCount >= MAX_ACCOUNT_FAILED_ATTEMPTS * 3) {
            // HARD LOCKOUT: Too many failures, requires admin unlock
            hardLockAccount(userId, username, clientIP);
            accountLockedCounter.increment();
            notifySecurityTeam(username, clientIP, "hard_lockout");
            return LoginResult.ACCOUNT_HARD_LOCKED;

        } else if (newFailedCount >= MAX_ACCOUNT_FAILED_ATTEMPTS) {
            // SOFT LOCKOUT: Temporary, can be bypassed with CAPTCHA/MFA
            softLockAccount(userId);
            accountLockedCounter.increment();

            // Notify user via email about suspicious activity
            sendSuspiciousActivityEmail(userId, clientIP);
            return LoginResult.REQUIRES_CAPTCHA;
        }

        return LoginResult.INVALID_CREDENTIALS;
    }

    private boolean isGlobalRateLimitExceeded() {
        long now = System.currentTimeMillis();
        if (now - lastGlobalReset > 60000) {
            globalFailedAttempts.set(0);
            lastGlobalReset = now;
        }
        return globalFailedAttempts.incrementAndGet() > MAX_GLOBAL_FAILED_PER_MINUTE;
    }

    private IPLimitResult checkIPRateLimit(String clientIP) {
        LoginAttemptTracker tracker = ipAttempts.computeIfAbsent(clientIP, 
            k -> new LoginAttemptTracker());

        tracker.cleanup();
        int failures = tracker.getFailureCount();

        if (failures >= MAX_IP_FAILED_ATTEMPTS * 2) {
            return IPLimitResult.BLOCKED;
        } else if (failures >= MAX_IP_FAILED_ATTEMPTS / 2) {
            return IPLimitResult.DELAYED;
        }
        return IPLimitResult.ALLOWED;
    }

    private void applyProgressiveDelay(String clientIP) {
        LoginAttemptTracker tracker = ipAttempts.get(clientIP);
        if (tracker != null) {
            int failures = tracker.getFailureCount();
            // Exponential backoff: 1s, 2s, 4s, 8s... up to 30s
            long delayMs = Math.min(1000L * (1L << (failures / 5)), 30000L);
            try {
                Thread.sleep(delayMs);
            } catch (InterruptedException e) {
                Thread.currentThread().interrupt();
            }
        }
    }

    private void softLockAccount(int userId) throws SQLException {
        String sql = "UPDATE users SET locked_until = ?, lock_type = 'SOFT' WHERE id = ?";
        PreparedStatement stmt = conn.prepareStatement(sql);
        stmt.setTimestamp(1, Timestamp.from(Instant.now().plus(Duration.ofMinutes(SOFT_LOCKOUT_MINUTES))));
        stmt.setInt(2, userId);
        stmt.executeUpdate();
    }

    private void hardLockAccount(int userId, String username, String clientIP) throws SQLException {
        String sql = "UPDATE users SET locked_until = ?, lock_type = 'HARD', lock_reason = ? WHERE id = ?";
        PreparedStatement stmt = conn.prepareStatement(sql);
        stmt.setTimestamp(1, Timestamp.from(Instant.now().plus(Duration.ofMinutes(HARD_LOCKOUT_MINUTES))));
        stmt.setString(2, "Excessive failed attempts from IP: " + clientIP);
        stmt.setInt(3, userId);
        stmt.executeUpdate();
    }

    private AccountStatus getAccountStatus(String username) throws SQLException {
        String sql = "SELECT locked_until, lock_type FROM users WHERE username = ?";
        PreparedStatement stmt = conn.prepareStatement(sql);
        stmt.setString(1, username);
        ResultSet rs = stmt.executeQuery();

        if (rs.next()) {
            Timestamp lockedUntil = rs.getTimestamp("locked_until");
            String lockType = rs.getString("lock_type");

            if (lockedUntil != null && lockedUntil.toInstant().isAfter(Instant.now())) {
                return "HARD".equals(lockType) ? AccountStatus.HARD_LOCKED : AccountStatus.SOFT_LOCKED;
            }
        }
        return AccountStatus.ACTIVE;
    }

    private void notifySecurityTeam(String username, String clientIP, String reason) {
        // Integration with PagerDuty/Slack/SIEM
        securityLogger.error("SECURITY_ALERT: {} for user {} from IP {}", reason, username, clientIP);
    }

    private void sendSuspiciousActivityEmail(int userId, String clientIP) {
        // Email notification to user about suspicious login attempts
    }

    private String sanitizeUserAgent(String userAgent) {
        if (userAgent == null) return "unknown";
        return userAgent.replaceAll("[^a-zA-Z0-9./;() -]", "").substring(0, Math.min(userAgent.length(), 200));
    }

    private void recordIPFailure(String clientIP) {
        ipAttempts.computeIfAbsent(clientIP, k -> new LoginAttemptTracker()).recordFailure();
    }

    private void resetIPAttempts(String clientIP) {
        ipAttempts.remove(clientIP);
    }

    private int incrementFailedAttempts(int userId) throws SQLException {
        String sql = "UPDATE users SET failed_attempts = failed_attempts + 1, last_failed_at = NOW() WHERE id = ? RETURNING failed_attempts";
        PreparedStatement stmt = conn.prepareStatement(sql);
        stmt.setInt(1, userId);
        ResultSet rs = stmt.executeQuery();
        return rs.next() ? rs.getInt(1) : 0;
    }

    private void resetFailedAttempts(int userId) throws SQLException {
        String sql = "UPDATE users SET failed_attempts = 0, locked_until = NULL, lock_type = NULL WHERE id = ?";
        PreparedStatement stmt = conn.prepareStatement(sql);
        stmt.setInt(1, userId);
        stmt.executeUpdate();
    }

    // Inner classes for tracking and results
    private static class LoginAttemptTracker {
        private final ConcurrentHashMap<Long, AtomicInteger> minuteBuckets = new ConcurrentHashMap<>();

        void recordFailure() {
            long minute = System.currentTimeMillis() / 60000;
            minuteBuckets.computeIfAbsent(minute, k -> new AtomicInteger()).incrementAndGet();
        }

        int getFailureCount() {
            long currentMinute = System.currentTimeMillis() / 60000;
            return minuteBuckets.entrySet().stream()
                .filter(e -> e.getKey() >= currentMinute - 15) // Last 15 minutes
                .mapToInt(e -> e.getValue().get())
                .sum();
        }

        void cleanup() {
            long cutoff = System.currentTimeMillis() / 60000 - 60;
            minuteBuckets.keySet().removeIf(k -> k < cutoff);
        }
    }

    enum LoginResult {
        SUCCESS, REQUIRES_MFA, REQUIRES_CAPTCHA, INVALID_CREDENTIALS,
        ACCOUNT_SOFT_LOCKED, ACCOUNT_HARD_LOCKED, IP_BLOCKED, RATE_LIMITED, SYSTEM_ERROR
    }

    enum AccountStatus { ACTIVE, SOFT_LOCKED, HARD_LOCKED }
    enum IPLimitResult { ALLOWED, DELAYED, BLOCKED }
}
```

**Defense in Depth Layers**:

1. **Global Rate Limiting**: Detects distributed attacks across all accounts
```java
if (globalFailedAttempts.incrementAndGet() > MAX_GLOBAL_FAILED_PER_MINUTE) {
    // Alert security team - possible coordinated attack
    return LoginResult.RATE_LIMITED;
}
```

2. **IP-Based Rate Limiting**: Prevents password spraying from single source
```java
// Block IP after too many failures across ANY account
if (ipTracker.getFailureCount() >= MAX_IP_FAILED_ATTEMPTS) {
    return LoginResult.IP_BLOCKED;
}
```

3. **Progressive Delays**: Slows down attacks without blocking legitimate users
```java
// Exponential backoff based on failure count
long delayMs = Math.min(1000L * (1L << (failures / 5)), 30000L);
Thread.sleep(delayMs);
```

4. **Soft vs Hard Lockout**: Prevents DoS while stopping attacks
```java
// Soft lock: User can bypass with CAPTCHA or MFA
// Hard lock: Requires admin intervention after severe abuse
```

**Additional Protections**:

- **CAPTCHA integration for soft-locked accounts**: Legitimate users can prove they're human
- **User notification emails**: Alert users to suspicious activity on their accounts
- **Metrics and monitoring**: Prometheus/Grafana dashboards for real-time attack detection
- **Security team alerts**: PagerDuty integration for hard lockouts and anomalies
- **Timing attack prevention**: Constant-time comparison even for non-existent users
- **User agent logging**: Helps identify automated attack tools
- **Distributed rate limiting**: Use Redis for rate limiting across multiple application servers

Storing credentials directly in source code is one of the most dangerous security practices. When credentials are hardcoded, they end up in version control, logs, error messages, and can be easily extracted by anyone with code access.

**VULNERABLE CODE**:

```go
package main

import (
	"database/sql"
	"fmt"
	"log"
	"net/http"

	_ "github.com/lib/pq"
)

// DANGEROUS: Hardcoded credentials in source code
const (
	DBHost     = "prod-db.company.internal"
	DBPort     = 5432
	DBUser     = "admin"
	DBPassword = "SuperSecret123!"  // VULNERABLE: Password in source
	DBName     = "production"
	APIKey     = "sk-prod-abc123xyz789"  // VULNERABLE: API key exposed
)

var db *sql.DB

func init() {
	connStr := fmt.Sprintf(
		"host=%s port=%d user=%s password=%s dbname=%s sslmode=disable",
		DBHost, DBPort, DBUser, DBPassword, DBName,
	)

	var err error
	db, err = sql.Open("postgres", connStr)
	if err != nil {
		log.Fatal(err)  // May log connection string with password
	}
}

func loginHandler(w http.ResponseWriter, r *http.Request) {
	// Application logic using hardcoded credentials
	fmt.Fprintf(w, "Connected to database")
}

func main() {
	http.HandleFunc("/login", loginHandler)
	log.Fatal(http.ListenAndServe(":8080", nil))
}
```

**Attack Vector**:
```bash
# Attacker searches Git repository
git log -p --all -S 'password' --source
git log -p --all -S 'secret' --source
strings ./compiled_binary | grep -i password
```

**Why This Is Dangerous**:
- Credentials are committed to version control history permanently
- Compiled binaries contain plaintext strings that can be extracted
- Anyone with repository access (contractors, ex-employees) can steal credentials
- Error messages and logs may expose connection strings
- Rotating credentials requires code changes and redeployment
- Secrets scanning tools flag these immediately in CI/CD

**SECURE VERSION**:

```go
package main

import (
	"context"
	"database/sql"
	"fmt"
	"log"
	"net/http"
	"os"
	"time"

	_ "github.com/lib/pq"
)

// Config holds database configuration from environment
type Config struct {
	DBHost     string
	DBPort     string
	DBUser     string
	DBPassword string
	DBName     string
	DBSSLMode  string
}

var db *sql.DB

// LoadConfig reads configuration from environment variables
func LoadConfig() (*Config, error) {
	config := &Config{
		DBHost:     os.Getenv("DB_HOST"),
		DBPort:     os.Getenv("DB_PORT"),
		DBUser:     os.Getenv("DB_USER"),
		DBPassword: os.Getenv("DB_PASSWORD"),
		DBName:     os.Getenv("DB_NAME"),
		DBSSLMode:  os.Getenv("DB_SSLMODE"),
	}

	// Validate required fields without logging values
	if config.DBHost == "" || config.DBPassword == "" {
		return nil, fmt.Errorf("required database configuration missing")
	}

	if config.DBSSLMode == "" {
		config.DBSSLMode = "require" // Secure default
	}

	return config, nil
}

func initDB() error {
	config, err := LoadConfig()
	if err != nil {
		return fmt.Errorf("configuration error: %w", err)
	}

	connStr := fmt.Sprintf(
		"host=%s port=%s user=%s password=%s dbname=%s sslmode=%s",
		config.DBHost, config.DBPort, config.DBUser,
		config.DBPassword, config.DBName, config.DBSSLMode,
	)

	db, err = sql.Open("postgres", connStr)
	if err != nil {
		// Log error without exposing credentials
		return fmt.Errorf("failed to open database connection")
	}

	// Verify connection with timeout
	ctx, cancel := context.WithTimeout(context.Background(), 5*time.Second)
	defer cancel()

	if err := db.PingContext(ctx); err != nil {
		return fmt.Errorf("failed to ping database")
	}

	return nil
}

func main() {
	if err := initDB(); err != nil {
		log.Fatalf("Database initialization failed: %v", err)
	}
	defer db.Close()

	http.HandleFunc("/login", loginHandler)
	log.Fatal(http.ListenAndServe(":8080", nil))
}
```

**Key Security Controls**:
- **Environment variables**: Credentials are injected at runtime, never in source code
- **Secure defaults**: SSL mode defaults to "require" for encrypted connections
- **No credential logging**: Error messages never include passwords or connection strings
- **Validation without exposure**: Required fields are checked but values are not logged

For production environments, you need a secrets management system that supports rotation, access control, audit logging, and dynamic credentials. HashiCorp Vault is the industry standard. Here's a production-grade implementation with automatic credential rotation.

**PRODUCTION PATTERN**:

```go
package main

import (
	"context"
	"database/sql"
	"encoding/json"
	"fmt"
	"log"
	"net/http"
	"os"
	"sync"
	"time"

	vault "github.com/hashicorp/vault/api"
	_ "github.com/lib/pq"
)

// SecureCredentialManager handles dynamic credential retrieval and rotation
type SecureCredentialManager struct {
	vaultClient  *vault.Client
	dbSecretPath string
	credentials  *DatabaseCredentials
	mu           sync.RWMutex
	leaseDuration time.Duration
	auditLogger  *log.Logger
}

// DatabaseCredentials holds dynamically generated credentials
type DatabaseCredentials struct {
	Username  string    `json:"username"`
	Password  string    `json:"password"`
	LeaseID   string    `json:"-"`
	ExpiresAt time.Time `json:"-"`
}

// NewSecureCredentialManager creates a new credential manager with Vault integration
func NewSecureCredentialManager(ctx context.Context) (*SecureCredentialManager, error) {
	// Configure Vault client
	config := vault.DefaultConfig()
	config.Address = os.Getenv("VAULT_ADDR")
	config.Timeout = 30 * time.Second

	// Enable TLS verification in production
	if os.Getenv("ENVIRONMENT") == "production" {
		config.ConfigureTLS(&vault.TLSConfig{
			CACert:     os.Getenv("VAULT_CACERT"),
			ClientCert: os.Getenv("VAULT_CLIENT_CERT"),
			ClientKey:  os.Getenv("VAULT_CLIENT_KEY"),
			Insecure:   false,
		})
	}

	client, err := vault.NewClient(config)
	if err != nil {
		return nil, fmt.Errorf("failed to create vault client: %w", err)
	}

	// Authenticate using Kubernetes service account (production)
	// or AppRole for other environments
	if err := authenticateVault(ctx, client); err != nil {
		return nil, fmt.Errorf("vault authentication failed: %w", err)
	}

	auditLogger := log.New(os.Stdout, "[AUDIT] ", log.LstdFlags|log.LUTC)

	manager := &SecureCredentialManager{
		vaultClient:  client,
		dbSecretPath: os.Getenv("VAULT_DB_SECRET_PATH"),
		auditLogger:  auditLogger,
	}

	// Fetch initial credentials
	if err := manager.refreshCredentials(ctx); err != nil {
		return nil, fmt.Errorf("initial credential fetch failed: %w", err)
	}

	// Start background credential rotation
	go manager.credentialRotationLoop(ctx)

	return manager, nil
}

// authenticateVault handles Vault authentication based on environment
func authenticateVault(ctx context.Context, client *vault.Client) error {
	env := os.Getenv("ENVIRONMENT")

	switch env {
	case "production", "staging":
		// Kubernetes authentication
		jwt, err := os.ReadFile("/var/run/secrets/kubernetes.io/serviceaccount/token")
		if err != nil {
			return fmt.Errorf("failed to read service account token: %w", err)
		}

		data := map[string]interface{}{
			"role": os.Getenv("VAULT_ROLE"),
			"jwt":  string(jwt),
		}

		secret, err := client.Logical().WriteWithContext(ctx, "auth/kubernetes/login", data)
		if err != nil {
			return fmt.Errorf("kubernetes auth failed: %w", err)
		}

		client.SetToken(secret.Auth.ClientToken)

	default:
		// AppRole for development (never hardcode these!)
		roleID := os.Getenv("VAULT_ROLE_ID")
		secretID := os.Getenv("VAULT_SECRET_ID")

		data := map[string]interface{}{
			"role_id":   roleID,
			"secret_id": secretID,
		}

		secret, err := client.Logical().WriteWithContext(ctx, "auth/approle/login", data)
		if err != nil {
			return fmt.Errorf("approle auth failed: %w", err)
		}

		client.SetToken(secret.Auth.ClientToken)
	}

	return nil
}

// refreshCredentials fetches new dynamic credentials from Vault
func (m *SecureCredentialManager) refreshCredentials(ctx context.Context) error {
	// Request dynamic database credentials
	secret, err := m.vaultClient.Logical().ReadWithContext(ctx, m.dbSecretPath)
	if err != nil {
		return fmt.Errorf("failed to read database credentials: %w", err)
	}

	if secret == nil || secret.Data == nil {
		return fmt.Errorf("no credentials returned from vault")
	}

	creds := &DatabaseCredentials{
		Username:  secret.Data["username"].(string),
		Password:  secret.Data["password"].(string),
		LeaseID:   secret.LeaseID,
		ExpiresAt: time.Now().Add(time.Duration(secret.LeaseDuration) * time.Second),
	}

	m.mu.Lock()
	m.credentials = creds
	m.leaseDuration = time.Duration(secret.LeaseDuration) * time.Second
	m.mu.Unlock()

	// Audit log credential fetch (never log actual credentials)
	m.auditLogger.Printf("Credentials refreshed, lease_id=%s, expires_at=%s",
		maskLeaseID(secret.LeaseID), creds.ExpiresAt.Format(time.RFC3339))

	return nil
}

// credentialRotationLoop automatically refreshes credentials before expiry
func (m *SecureCredentialManager) credentialRotationLoop(ctx context.Context) {
	for {
		m.mu.RLock()
		// Refresh at 75% of lease duration
		refreshInterval := time.Duration(float64(m.leaseDuration) * 0.75)
		m.mu.RUnlock()

		if refreshInterval < time.Minute {
			refreshInterval = time.Minute
		}

		select {
		case <-ctx.Done():
			m.auditLogger.Printf("Credential rotation loop stopped")
			return
		case <-time.After(refreshInterval):
			if err := m.refreshCredentials(ctx); err != nil {
				m.auditLogger.Printf("ERROR: Credential refresh failed: %v", err)
				// Retry with exponential backoff
				time.Sleep(30 * time.Second)
				continue
			}
		}
	}
}

// GetConnectionString returns a secure connection string
func (m *SecureCredentialManager) GetConnectionString() string {
	m.mu.RLock()
	defer m.mu.RUnlock()

	return fmt.Sprintf(
		"host=%s port=%s user=%s password=%s dbname=%s sslmode=require",
		os.Getenv("DB_HOST"),
		os.Getenv("DB_PORT"),
		m.credentials.Username,
		m.credentials.Password,
		os.Getenv("DB_NAME"),
	)
}

// maskLeaseID partially masks lease ID for audit logs
func maskLeaseID(leaseID string) string {
	if len(leaseID) <= 8 {
		return "***"
	}
	return leaseID[:4] + "..." + leaseID[len(leaseID)-4:]
}

// SecureDBPool manages database connections with automatic credential refresh
type SecureDBPool struct {
	db          *sql.DB
	credManager *SecureCredentialManager
	mu          sync.RWMutex
}

// NewSecureDBPool creates a database pool with dynamic credentials
func NewSecureDBPool(ctx context.Context, credManager *SecureCredentialManager) (*SecureDBPool, error) {
	db, err := sql.Open("postgres", credManager.GetConnectionString())
	if err != nil {
		return nil, fmt.Errorf("failed to open database: %w", err)
	}

	// Production connection pool settings
	db.SetMaxOpenConns(25)
	db.SetMaxIdleConns(5)
	db.SetConnMaxLifetime(5 * time.Minute)
	db.SetConnMaxIdleTime(1 * time.Minute)

	// Verify connection
	if err := db.PingContext(ctx); err != nil {
		db.Close()
		return nil, fmt.Errorf("database ping failed: %w", err)
	}

	return &SecureDBPool{
		db:          db,
		credManager: credManager,
	}, nil
}

// Query executes a query with automatic connection recovery
func (p *SecureDBPool) Query(ctx context.Context, query string, args ...interface{}) (*sql.Rows, error) {
	p.mu.RLock()
	db := p.db
	p.mu.RUnlock()

	rows, err := db.QueryContext(ctx, query, args...)
	if err != nil {
		// Check if error is due to credential expiry
		if isAuthError(err) {
			// Reconnect with fresh credentials
			if reconnectErr := p.reconnect(ctx); reconnectErr != nil {
				return nil, fmt.Errorf("reconnection failed: %w", reconnectErr)
			}
			// Retry query
			return p.db.QueryContext(ctx, query, args...)
		}
		return nil, err
	}

	return rows, nil
}

func isAuthError(err error) bool {
	// Check for PostgreSQL authentication failure codes
	errStr := err.Error()
	return contains(errStr, "authentication failed") ||
		contains(errStr, "password authentication failed") ||
		contains(errStr, "28P01") // PostgreSQL auth failure code
}

func contains(s, substr string) bool {
	return len(s) >= len(substr) && (s == substr || len(s) > 0 && containsImpl(s, substr))
}

func containsImpl(s, substr string) bool {
	for i := 0; i <= len(s)-len(substr); i++ {
		if s[i:i+len(substr)] == substr {
			return true
		}
	}
	return false
}

func (p *SecureDBPool) reconnect(ctx context.Context) error {
	p.mu.Lock()
	defer p.mu.Unlock()

	// Close existing connection
	if p.db != nil {
		p.db.Close()
	}

	// Open new connection with current credentials
	db, err := sql.Open("postgres", p.credManager.GetConnectionString())
	if err != nil {
		return err
	}

	if err := db.PingContext(ctx); err != nil {
		db.Close()
		return err
	}

	p.db = db
	return nil
}

func main() {
	ctx, cancel := context.WithCancel(context.Background())
	defer cancel()

	// Initialize secure credential manager
	credManager, err := NewSecureCredentialManager(ctx)
	if err != nil {
