class RateLimiter {
    public function isGlobalLimitExceeded(): bool {
        $key = 'global_login_count:' . date('YmdHi');
        $count = $this->redis->incr($key);
        $this->redis->expire($key, 120);
        return $count > self::GLOBAL_THRESHOLD_PER_MINUTE;
    }
}
