import os
import logging
import hashlib
from abc import ABC, abstractmethod
from typing import Optional, Dict, Any
from functools import lru_cache
from datetime import datetime, timedelta
import threading

logger = logging.getLogger(__name__)


class SecretsProvider(ABC):
    """Abstract base class for secrets providers."""

    @abstractmethod
    def get_secret(self, secret_name: str) -> str:
        pass

    @abstractmethod
    def rotate_secret(self, secret_name: str) -> bool:
        pass


class AWSSecretsManagerProvider(SecretsProvider):
    """AWS Secrets Manager implementation with caching and rotation."""

    def __init__(self, region: str = None):
        import boto3
        from botocore.exceptions import ClientError

        self.region = region or os.environ.get('AWS_REGION', 'us-east-1')
        self.client = boto3.client('secretsmanager', region_name=self.region)
        self._cache: Dict[str, Dict[str, Any]] = {}
        self._cache_ttl = timedelta(minutes=5)
        self._lock = threading.Lock()
        self.ClientError = ClientError

    def get_secret(self, secret_name: str) -> str:
        """Retrieve secret with caching and automatic refresh."""
        with self._lock:
            cached = self._cache.get(secret_name)
            if cached and datetime.utcnow() < cached['expires_at']:
                logger.debug(f"Cache hit for secret: {self._hash_name(secret_name)}")
                return cached['value']

        try:
            response = self.client.get_secret_value(SecretId=secret_name)
            secret_value = response.get('SecretString')

            if not secret_value:
                raise ValueError(f"Secret {secret_name} has no string value")

            with self._lock:
                self._cache[secret_name] = {
                    'value': secret_value,
                    'expires_at': datetime.utcnow() + self._cache_ttl,
                    'version_id': response.get('VersionId')
                }

            logger.info(
                f"Secret retrieved: name_hash={self._hash_name(secret_name)}, "
                f"version={response.get('VersionId', 'unknown')[:8]}"
            )
            return secret_value

        except self.ClientError as e:
            error_code = e.response['Error']['Code']
            logger.error(
                f"Failed to retrieve secret: name_hash={self._hash_name(secret_name)}, "
                f"error={error_code}"
            )
            raise RuntimeError(f"Cannot retrieve secret: {error_code}")

    def rotate_secret(self, secret_name: str) -> bool:
        """Trigger secret rotation."""
        try:
            self.client.rotate_secret(SecretId=secret_name)
            with self._lock:
                self._cache.pop(secret_name, None)
            logger.info(f"Secret rotation initiated: {self._hash_name(secret_name)}")
            return True
        except self.ClientError as e:
            logger.error(f"Secret rotation failed: {e.response['Error']['Code']}")
            return False

    @staticmethod
    def _hash_name(name: str) -> str:
        """Hash secret name for safe logging."""
        return hashlib.sha256(name.encode()).hexdigest()[:12]


class HashiCorpVaultProvider(SecretsProvider):
    """HashiCorp Vault implementation with token renewal."""

