class SecureCredentialManager:
    """Production credential manager with defense in depth."""

    def __init__(self):
        self.provider = self._initialize_provider()
        self._validate_required_secrets()

    def _initialize_provider(self) -> SecretsProvider:
        """Select secrets provider based on environment."""
        provider_type = os.environ.get('SECRETS_PROVIDER', 'aws')

        if provider_type == 'aws':
            return AWSSecretsManagerProvider()
        elif provider_type == 'vault':
            return HashiCorpVaultProvider()
        else:
            raise ValueError(f"Unknown secrets provider: {provider_type}")

    def _validate_required_secrets(self):
        """Validate all required secrets are accessible at startup."""
        required = ['database/credentials', 'api/stripe-key', 'api/internal-key']
        missing = []

        for secret_name in required:
            try:
                self.provider.get_secret(secret_name)
            except Exception:
                missing.append(secret_name)

        if missing:
            logger.critical(f"Missing required secrets: {len(missing)} secrets unavailable")
            raise RuntimeError("Application cannot start: missing required secrets")

        logger.info(f"All {len(required)} required secrets validated")

    def get_database_credentials(self) -> Dict[str, str]:
        """Retrieve database credentials with audit logging."""
        import json

        secret_json = self.provider.get_secret('database/credentials')
        creds = json.loads(secret_json)

        logger.info(
            "Database credentials accessed",
            extra={
                'event_type': 'secret_access',
                'secret_name': 'database/credentials',
                'timestamp': datetime.utcnow().isoformat()
            }
        )

        return {
            'host': creds['host'],
            'port': creds.get('port', 5432),
            'username': creds['username'],
            'password': creds['password'],
            'database': creds['database']
        }

    def get_api_key(self, service: str) -> str:
        """Retrieve API key with validation."""
        allowed_services = {'stripe', 'twilio', 'sendgrid', 'internal'}

        if service not in allowed_services:
            logger.warning(f"Attempt to access unknown API key: {service}")
            raise ValueError(f"Unknown service: {service}")

        return self.provider.get_secret(f'api/{service}-key')
