  const attempts = failedAttempts.get(username);
  if (!attempts) return false;

  if (attempts.lockedUntil && Date.now() < attempts.lockedUntil) {
    return true;
  }

  // Clean up expired lockout
  if (attempts.lockedUntil && Date.now() >= attempts.lockedUntil) {
    failedAttempts.delete(username);
  }

  return false;
}

function recordFailedAttempt(username, ip) {
  const now = Date.now();
  let attempts = failedAttempts.get(username) || { count: 0, firstAttempt: now, ips: new Set() };

  // Reset if outside attempt window
  if (now - attempts.firstAttempt > ATTEMPT_WINDOW_MS) {
    attempts = { count: 0, firstAttempt: now, ips: new Set() };
  }

  attempts.count++;
  attempts.ips.add(ip);

  if (attempts.count >= MAX_FAILED_ATTEMPTS) {
    attempts.lockedUntil = now + LOCKOUT_DURATION_MS;
    console.warn(`Account locked: ${username} after ${attempts.count} failed attempts from IPs: ${[...attempts.ips].join(', ')}`);
  }

  failedAttempts.set(username, attempts);
  return attempts.count;
}

function clearFailedAttempts(username) {
