      body: `secret=${process.env.RECAPTCHA_SECRET}&response=${token}`
    });
    const data = await response.json();
    return data.success && data.score >= 0.5;
  } catch (error) {
    console.error('CAPTCHA verification failed:', error);
    return false; // Fail closed
  }
}

// Generate request fingerprint for bot detection
function getRequestFingerprint(req) {
  const components = [
    req.headers['user-agent'] || '',
    req.headers['accept-language'] || '',
    req.headers['accept-encoding'] || ''
  ];
  return crypto.createHash('sha256').update(components.join('|')).digest('hex').substring(0, 16);
}

app.post('/api/login', async (req, res) => {
  const { username, password, captchaToken } = req.body;
  const clientIP = req.headers['x-forwarded-for']?.split(',')[0] || req.ip;
  const fingerprint = getRequestFingerprint(req);

  const auditLog = {
    timestamp: new Date().toISOString(),
    username,
    ip: clientIP,
    fingerprint,
    userAgent: req.headers['user-agent'],
    result: null
  };

  try {
    // Layer 1: Check global rate limit
    try {
      await globalLimiter.consume('global');
    } catch (rejRes) {
      auditLog.result = 'BLOCKED_GLOBAL_RATELIMIT';
      console.warn(JSON.stringify(auditLog));
      return res.status(429).json({ error: 'Service temporarily unavailable' });
    }

    // Layer 2: Check emergency lockout
    const emergencyLock = await redis.get(`emergency_lock:${username}`);
    if (emergencyLock) {
      auditLog.result = 'BLOCKED_EMERGENCY_LOCKOUT';
      console.warn(JSON.stringify(auditLog));
      return res.status(423).json({ 
        error: 'Account locked for security reasons. Contact support.',
        supportCode: crypto.randomUUID()
      });
    }

    // Layer 3: Check for distributed attack pattern
    const attackStatus = await attackDetector.isUnderDistributedAttack(username);
    if (attackStatus.underAttack) {
      await attackDetector.triggerEmergencyLockout(username, 
        `Distributed attack detected: ${attackStatus.totalAttempts} attempts from ${attackStatus.uniqueIPs} IPs`);

      auditLog.result = 'BLOCKED_DISTRIBUTED_ATTACK';
      console.warn(JSON.stringify(auditLog));
      return res.status(423).json({ 
        error: 'Account locked for security reasons. Contact support.',
        supportCode: crypto.randomUUID()
      });
    }

    // Layer 4: Check IP rate limit
    try {
      await ipLimiter.consume(clientIP);
    } catch (rejRes) {
      auditLog.result = 'BLOCKED_IP_RATELIMIT';
      console.warn(JSON.stringify(auditLog));
      const retryAfter = Math.ceil(rejRes.msBeforeNext / 1000);
      res.set('Retry-After', retryAfter);
      return res.status(429).json({ 
        error: 'Too many attempts from this location',
        retryAfter
      });
    }

    // Layer 5: Check username lockout
    try {
      await usernameLimiter.consume(username);
    } catch (rejRes) {
      auditLog.result = 'BLOCKED_ACCOUNT_LOCKED';
      console.warn(JSON.stringify(auditLog));

      // Require CAPTCHA after lockout expires
      await redis.setex(`require_captcha:${username}`, 3600, 'true');

      const retryAfter = Math.ceil(rejRes.msBeforeNext / 1000);
      return res.status(423).json({ 
        error: 'Account temporarily locked',
        retryAfter
      });
    }

    // Layer 6: Check if CAPTCHA required
    const captchaRequired = await redis.get(`require_captcha:${username}`);
    if (captchaRequired) {
      const captchaValid = await verifyCaptcha(captchaToken);
      if (!captchaValid) {
        auditLog.result = 'BLOCKED_CAPTCHA_REQUIRED';
        console.warn(JSON.stringify(auditLog));
        return res.status(403).json({ 
          error: 'CAPTCHA verification required',
          captchaRequired: true
        });
      }
    }

    // Perform authentication
    const result = await pool.query(
      'SELECT id, username, password_hash FROM users WHERE username = $1',
      [username]
    );

    if (result.rows.length === 0) {
      await attackDetector.recordAttempt(username, clientIP);
      auditLog.result = 'FAILED_USER_NOT_FOUND';
      console.info(JSON.stringify(auditLog));
      return res.status(401).json({ error: 'Invalid credentials' });
    }

    const user = result.rows[0];
    const validPassword = await bcrypt.compare(password, user.password_hash);

    if (!validPassword) {
      await attackDetector.recordAttempt(username, clientIP);

      // Consume from combined limiter on failure
      try {
        await combinedLimiter.consume(`${username}:${clientIP}`);
      } catch (e) {
        // Combined limit exceeded - suspicious pattern
        console.warn(`Suspicious pattern: repeated failures from ${clientIP} for ${username}`);
      }

      auditLog.result = 'FAILED_INVALID_PASSWORD';
      console.info(JSON.stringify(auditLog));
      return res.status(401).json({ error: 'Invalid credentials' });
    }

    // SUCCESS - Reset all limiters for this user
    await Promise.all([
      usernameLimiter.delete(username),
      combinedLimiter.delete(`${username}:${clientIP}`),
      redis.del(`require_captcha:${username}`)
    ]);

    const token = generateToken(user.id);

    auditLog.result = 'SUCCESS';
    console.info(JSON.stringify(auditLog));

    res.json({ token });

  } catch (error) {
    auditLog.result = 'ERROR';
    auditLog.error = error.message;
    console.error(JSON.stringify(auditLog));
    res.status(500).json({ error: 'Internal server error' });
  }
});

function generateToken(userId) {
  // Implementation using JWT or similar
  return crypto.randomBytes(32).toString('hex');
}

module.exports = app;
